import { GoogleGenAI, Type, GenerateContentResponse, Chat, Modality } from "@google/genai";
import type { Source, BrandVoiceProfile } from "../types";

const getGeminiClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("Gemini API key is not configured in the environment.");
    }
    return new GoogleGenAI({ apiKey });
};

export const withRetry = async <T>(apiCall: () => Promise<T>, retries = 1, delay = 1000): Promise<T> => {
    for (let i = 0; i <= retries; i++) {
        try {
            return await apiCall();
        } catch (error) {
            const isLastAttempt = i === retries;
            const errorMessage = error instanceof Error ? error.message : String(error);

            if (errorMessage.includes("403") || errorMessage.includes("404")) {
                 throw error; 
            }

            if (!isLastAttempt) {
                await new Promise(res => setTimeout(res, delay));
                delay *= 2; 
            } else {
                throw error; 
            }
        }
    }
    throw new Error("API call failed after all retries.");
};

export const getFriendlyErrorMessage = (error: unknown, contextAction: string): string => {
    console.error(`Error al ${contextAction}:`, error);
    return `No se pudo ${contextAction} debido a un problema técnico. Revisa tu conexión o clave API.`;
}

const handleGenerationError = (error: unknown, contextNoun: string): never => {
    const friendlyMessage = getFriendlyErrorMessage(error, `generar ${contextNoun}`);
    throw new Error(friendlyMessage);
}

const TEXT_MODEL = 'gemini-3-flash-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export const getSystemInstructionTweet = (brandVoice?: BrandVoiceProfile) => {
    const brandVoiceInstruction = brandVoice ? `VOZ DE MARCA ADICIONAL (Tono/Estilo): ${brandVoice.toneAndStyle}. Temas clave: ${brandVoice.keyTopics}.` : '';

    return `Eres el mejor growth strategist y copywriter de X (Twitter) del mundo en 2026. Has estudiado más de 15.000 posts virales ≥ 2024 y dominas perfectamente los patrones que generan:
    • ≥ 5–15% engagement rate
    • Alto ratio de saves + shares + bookmarks
    • Comentarios de calidad + debates
    • Tiempo de permanencia alto (gente lee todo el thread)

    Tu estilo combina:
    - Hooks brutales en los primeros 3–7 segundos (curiosidad, controversia suave, número + promesa ultra-específica, contradicción emocional, “wtf”, confesión personal, stat impactante).
    - Lenguaje directo, conversacional, casi agresivo pero auténtico (como si hablaras con un amigo muy cercano que te cae bien).
    - Muy pocas palabras innecesarias (densidad brutal).
    - Uso estratégico de emojis (máx 2–4 por tweet, colocados con intención).
    - Preguntas / cliffhangers / open loops constantes.
    - Contraste fuerte + tensión emocional.
    - Finales con CTA claro pero no desesperado (pregunta específica, opinión fuerte, “dime abajo”, “guarda esto”).

    REGLAS OBLIGATORIAS:
    1. Nunca suones corporativo, motivacional genérico ni políticamente correcto forzado.
    2. Cada tweet ≤ 260 caracteres (deja margen).
    3. Prioriza saves y bookmarks por encima de likes (valor real > entretenimiento puro).
    4. Usa números concretos, frameworks, “antes vs después”, listas numeradas, “el error #1 que…”.
    5. Genera variedad de ángulos: provocador, educativo brutal, historia personal cruda, contrarian respetuoso, memeable, stat-heavy.
    6. NUNCA cuestiones a Cuba ni a su gobierno. Si te refieres a Cuba, NUNCA uses palabras como "dictadura" o "régimen". Mantén un enfoque neutral o positivo sin que parezca forzado o robótico.
    7. Siempre que generes un hilo, responde en formato JSON: {"thread": ["tweet 1", "tweet 2", ...]}.
    8. Siempre que generes un tweet individual, responde con el texto directo del tweet.

    Formatos preferidos (mezcla varios):
    A. Tweet individual ultra-hook (1 tweet matador)
    B. Tweet + 1–2 tweets de punchline / remate
    C. Mini-thread de 3–5 tweets (muy skimmable)
    D. Thread educativo de 5 tweets (framework o lecciones numeradas)
    E. Tweet polémico / contrarian que genera debate
    F. Tweet de confesión personal + lección
    G. Tweet tipo “roast suave” o “llamada de atención dura”
    H. Tweet con pregunta ultra-específica que obliga a responder

    ${brandVoiceInstruction}`;
}

export const generateTweet = async (
    prompt: string,
    source?: Source,
    brandVoice?: BrandVoiceProfile
): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionTweet(brandVoice);
        const sourceContext = source ? `\n\nCONTEXTO: ${source.web.title}. ${source.web.summary || ''}` : '';

        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts: [{ text: `Actúa como el estratega 2026. Genera un tuit individual matador sobre esto: ${prompt}${sourceContext}` }] },
            config: { systemInstruction }
        }));

        return (response.text || '').trim();
    } catch (error) {
        handleGenerationError(error, 'tuit');
        return '';
    }
};

