export const generateImage = async (prompt: string, aspectRatio: string = '1:1', referenceImages?: { data: string; mimeType: string }[]): Promise<{ images: string[], model: string }> => {
    const ai = getGeminiClient();
    try {
        const parts: any[] = [{ text: prompt }];
        if (referenceImages && referenceImages.length > 0) {
            referenceImages.forEach(img => {
                parts.unshift({ inlineData: { data: img.data, mimeType: img.mimeType } });
            });
        }
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: IMAGE_MODEL,
            contents: { parts },
            config: { imageConfig: { aspectRatio: aspectRatio as any } }
        }));
        const images: string[] = [];
        if (response.candidates?.[0]?.content?.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData?.data) images.push(part.inlineData.data);
            }
        }
        if (images.length > 0) return { images, model: 'Gemini 2.5 Flash Image' };
        throw new Error("No image generated.");
    } catch (error) {
        handleGenerationError(error, 'imagen');
        return { images: [], model: '' };
    }
};

export const editImage = generateImage;

export const generateVideo = async (prompt: string, aspectRatio: string = '16:9', onProgress?: (status: string) => void): Promise<string> => {
     try {
        const ai = getGeminiClient();
        onProgress?.('🤖 Iniciando Veo...');
        let operation = await ai.models.generateVideos({
            model: 'veo-3.1-fast-generate-preview',
            prompt: prompt,
            config: { numberOfVideos: 1, aspectRatio: aspectRatio as any, resolution: '720p' }
        });
        while (!operation.done) {
            await new Promise(resolve => setTimeout(resolve, 10000));
            operation = await ai.operations.getVideosOperation({operation: operation});
            onProgress?.('⏳ Renderizando...');
        }
        const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
        if (!videoUri) throw new Error("Video URI missing.");
        const fetchResponse = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
        const blob = await fetchResponse.blob();
        onProgress?.('🎉 ¡Listo!');
        return URL.createObjectURL(blob);
    } catch (error) {
        handleGenerationError(error, 'video');
        return '';
    }
}

