                      id: `tweet-${Date.now()}-${i}`,
                      content,
                      media: null,
                      isLoadingMedia: false,
                      isCopied: false,
                      isRegenerating: false,
                  })));
                  setChatMessages(prev => [...prev, { author: 'user', content: `Generar hilo numerado sobre: ${context}` }, { author: 'ai', content: `Hilo viral numerado listo en el preview.` }]);
              }
