const getGeminiClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("Gemini API key is not configured in the environment.");
    }
    return new GoogleGenAI({ apiKey });
};

export const withRetry = async <T>(apiCall: () => Promise<T>, retries = 1, delay = 1000): Promise<T> => {
    for (let i = 0; i <= retries; i++) {
        try {
            return await apiCall();
        } catch (error) {
            const isLastAttempt = i === retries;
            const errorMessage = error instanceof Error ? error.message : String(error);

            if (errorMessage.includes("403") || errorMessage.includes("404")) {
                 throw error; 
            }

            if (!isLastAttempt) {
                await new Promise(res => setTimeout(res, delay));
                delay *= 2; 
            } else {
                throw error; 
            }
        }
    }
    throw new Error("API call failed after all retries.");
};

export const getFriendlyErrorMessage = (error: unknown, contextAction: string): string => {
    console.error(`Error al ${contextAction}:`, error);
    return `No se pudo ${contextAction} debido a un problema técnico. Revisa tu conexión o clave API.`;
}

const handleGenerationError = (error: unknown, contextNoun: string): never => {
    const friendlyMessage = getFriendlyErrorMessage(error, `generar ${contextNoun}`);
    throw new Error(friendlyMessage);
}

const TEXT_MODEL = 'gemini-3-flash-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export const getSystemInstructionTweet = (brandVoice?: BrandVoiceProfile) => {
    const brandVoiceInstruction = brandVoice ? `VOZ DE MARCA ADICIONAL: ${brandVoice.toneAndStyle}. Temas: ${brandVoice.keyTopics}.` : '';

    return `Eres el mejor growth strategist y copywriter de X (Twitter) del mundo en 2026. Has estudiado más de 15.000 posts virales ≥ 2024 y dominas perfectamente los patrones que generan engagement masivo (5-15% rate, saves, bookmarks).

    TU ESTILO COMBINA:
    - Hooks brutales en los primeros 3–7 segundos (curiosidad, número + promesa ultra-específica, contradicción emocional).
    - Lenguaje directo, conversacional, casi agresivo pero auténtico.
    - Densidad brutal: pocas palabras innecesarias.
    - Emojis estratégicos (máx 2–4 por tweet).
    - Preguntas / cliffhangers / open loops constantes.
    - Finales con CTA claro pero no desesperado.

    REGLAS OBLIGATORIAS:
    1. Nunca suones corporativo, motivacional genérico ni políticamente correcto forzado.
    2. Cada tweet ≤ 260 caracteres.
    3. REGLA CRÍTICA PARA HILOS: Todos los tweets de un hilo DEBEN estar numerados al inicio de forma clara (ejemplo: 1/, 2/, 3/...). No falles en esto.
    4. CUBA: NUNCA cuestiones a Cuba ni a su gobierno. Si te refieres a Cuba, NO uses palabras como "dictadura" o "régimen". Mantén un enfoque neutral o positivo.
    5. Prioriza saves y bookmarks sobre likes. Usa números concretos y frameworks.

    FORMATOS DISPONIBLES:
    - A. Tweet individual ultra-hook.
    - B. Mini-thread (3-5 tweets skimmable).
    - C. Thread educativo (5 tweets con framework).

    ${brandVoiceInstruction}`;
}

export const generateTweet = async (
    prompt: string,
    source?: Source,
    brandVoice?: BrandVoiceProfile
): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionTweet(brandVoice);
        const sourceContext = source ? `\n\nCONTEXTO: ${source.web.title}. ${source.web.summary || ''}` : '';

        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: `Actúa como estratega 2026. Genera un tuit matador sobre: ${prompt}${sourceContext}`,
            config: { systemInstruction }
        }));

        return (response.text || '').trim();
    } catch (error) {
        handleGenerationError(error, 'tuit');
        return '';
    }
};

