                {filePreviews.length > 0 && (
                    <div className="grid grid-cols-3 gap-2 mb-3">
                        {filePreviews.map((src, index) => (
                            <div key={index} className="relative aspect-square rounded-lg overflow-hidden border border-border-primary group">
