            contents: { parts: [{ text: `Reescribe esto como estratega 2026: "${tweetContent}"` }] },
            config: { systemInstruction: getSystemInstructionTweet() }
        }));
        return (response.text || '').trim();
    } catch (error) {
        handleGenerationError(error, 'regeneración');
        return '';
