            </div>

            <div className="lg:sticky lg:top-28 h-fit max-h-[calc(100vh-8rem)]">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-2xl font-bold text-text-primary">Preview Viral</h3>
                    <button onClick={handleStartNew} className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-colors bg-bg-secondary border-2 border-text-primary text-text-secondary hover:bg-border-primary hover:text-text-primary">
                        <PlusIcon className="h-5 w-5" /> Nuevo
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 max-h-[calc(100vh-12rem)] space-y-4">
                      {tweets.map((tweet, index) => (
                          <div key={tweet.id} ref={el => { tweetPreviewRefs.current[index] = el; }}>
                              <TweetPreview
                                  tweet={{ id: tweet.id, content: tweet.content, author: DEFAULT_USER, media: tweet.media || undefined, public_metrics: { like_count: 0, retweet_count: 0, impression_count: 0, reply_count: 0, quote_count: 0 }, created_at: new Date().toISOString(), }}
                                  editableTweet={tweet}
                                  isGenerating={isLoading}
                                  onCopy={() => handleCopy(tweet.content, index)}
                                  onGenerateMedia={(type) => openMediaPromptModal(type, index)}
                                  onUploadMedia={() => { setMediaTargetIndex(index); fileInputRef.current?.click(); }}
                                  onRemoveMedia={() => handleRemoveMedia(index)}
                                  onTweetChange={(value) => handleTweetChange(index, value)}
                                  onRegenerate={() => handleRegenerateTweet(index)}
                                  onDeleteTweet={() => handleDeleteTweet(index)}
