                      ))}
                      {tweets.length > 0 && tweets.some(t => t.content) && (
                        <button onClick={addTweetToThread} className="w-full py-3 border-2 border-dashed border-border-primary rounded-xl text-text-secondary hover:text-accent-primary hover:border-accent-primary transition-all font-bold text-sm">
