import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Blob } from '@google/genai';
import { encode, decode, decodeAudioData } from '../utils/audioUtils';
import MicrophoneIcon from './icons/MicrophoneIcon';
import LoaderIcon from './icons/LoaderIcon';

const LiveConversation: React.FC = () => {
    const [isConnecting, setIsConnecting] = useState(false);
    const [isActive, setIsActive] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [transcript, setTranscript] = useState<{ author: 'user' | 'ai', text: string }[]>([]);

    const sessionPromiseRef = useRef<Promise<any> | null>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const inputAudioContextRef = useRef<AudioContext | null>(null);
    const outputAudioContextRef = useRef<AudioContext | null>(null);
    const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
    const nextStartTimeRef = useRef<number>(0);
    const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

    const currentInputTranscription = useRef('');
    const currentOutputTranscription = useRef('');

    const cleanup = () => {
        setIsActive(false);
        setIsConnecting(false);

        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
            streamRef.current = null;
        }
        if (scriptProcessorRef.current) {
            scriptProcessorRef.current.disconnect();
            scriptProcessorRef.current = null;
        }
        if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
            inputAudioContextRef.current.close();
            inputAudioContextRef.current = null;
        }
        if (outputAudioContextRef.current && outputAudioContextRef.current.state !== 'closed') {
            sourcesRef.current.forEach(source => source.stop());
            sourcesRef.current.clear();
            outputAudioContextRef.current.close();
            outputAudioContextRef.current = null;
        }
        sessionPromiseRef.current?.then(session => session.close());
        sessionPromiseRef.current = null;
    };

    const handleToggleConversation = async () => {
        if (isActive || isConnecting) {
            cleanup();
            return;
        }

        setIsConnecting(true);
        setError(null);
        setTranscript([]);

        try {
            if (!process.env.API_KEY) throw new Error("API_KEY environment variable not set.");
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            streamRef.current = stream;

            inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            nextStartTimeRef.current = 0;

            sessionPromiseRef.current = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-12-2025',
                callbacks: {
                    onopen: () => {
                        const inputSource = inputAudioContextRef.current!.createMediaStreamSource(stream);
                        const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);
                        scriptProcessorRef.current = scriptProcessor;

                        scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                            const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);
                            const pcmBlob: Blob = {
                                data: encode(new Uint8Array(new Int16Array(inputData.map(x => x * 32768)).buffer)),
                                mimeType: 'audio/pcm;rate=16000',
                            };
                            sessionPromiseRef.current?.then((session) => {
                                session.sendRealtimeInput({ media: pcmBlob });
                            });
                        };
                        inputSource.connect(scriptProcessor);
                        scriptProcessor.connect(inputAudioContextRef.current!.destination);

                        setIsConnecting(false);
                        setIsActive(true);
                    },
                    onmessage: async (message: LiveServerMessage) => {
                        const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                        if (base64Audio) {
                            const outputCtx = outputAudioContextRef.current!;
                            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
                            const audioBuffer = await decodeAudioData(decode(base64Audio), outputCtx, 24000, 1);

                            const source = outputCtx.createBufferSource();
                            source.buffer = audioBuffer;
                            source.connect(outputCtx.destination);

                            sourcesRef.current.add(source);
                            source.onended = () => {
                                sourcesRef.current.delete(source);
                            };

                            source.start(nextStartTimeRef.current);
                            nextStartTimeRef.current += audioBuffer.duration;
                        }

                        if (message.serverContent?.interrupted) {
                            sourcesRef.current.forEach(source => source.stop());
                            sourcesRef.current.clear();
                            nextStartTimeRef.current = 0;
                        }

                        if (message.serverContent?.inputTranscription) {
                            currentInputTranscription.current += message.serverContent.inputTranscription.text;
                        }
                        if (message.serverContent?.outputTranscription) {
                            currentOutputTranscription.current += message.serverContent.outputTranscription.text;
                        }

                        if (message.serverContent?.turnComplete) {
                            setTranscript(prev => [
                                ...prev,
                                { author: 'user', text: currentInputTranscription.current },
                                { author: 'ai', text: currentOutputTranscription.current }
                            ]);
                            currentInputTranscription.current = '';
                            currentOutputTranscription.current = '';
                        }
                    },
                    onerror: (e: ErrorEvent) => {
                        setError(`Error táctico: ${e.message || 'Sin permisos (403)'}`);
                        cleanup();
                    },
                    onclose: () => cleanup(),
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    inputAudioTranscription: {},
                    outputAudioTranscription: {},
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
                    },
                    systemInstruction: 'Eres un estratega de contenido growth experto.',
                },
            });
        } catch (err) {
            setError(`Fallo al iniciar: ${err instanceof Error ? err.message : "403"}`);
            cleanup();
        }
    };

    useEffect(() => {
        return () => cleanup();
    }, []);

    return (
        <div className="max-w-2xl mx-auto text-center animate-fade-in">
            <h1 className="text-3xl font-bold text-text-primary mb-2">Live Estratega</h1>
            <p className="text-text-secondary mb-8">Habla con la IA en tiempo real sobre tu estrategia.</p>

            <button 
                onClick={handleToggleConversation} 
                disabled={isConnecting}
                className={`mx-auto w-32 h-32 rounded-full flex items-center justify-center transition-all duration-300 border-4 ${isActive ? 'border-danger bg-danger/20' : 'border-accent-primary bg-accent-primary/10'}`}
            >
                {isConnecting ? <LoaderIcon className="h-12 w-12 text-accent-primary"/> : <MicrophoneIcon className={`h-12 w-12 ${isActive ? 'text-danger' : 'text-accent-primary'}`} />}
            </button>

            <p className="mt-4 font-semibold text-lg h-6">
                {isConnecting ? "Conectando..." : isActive ? "Sesión Activa" : "Click para Hablar"}
            </p>
            {error && <p className="mt-2 text-sm text-danger">{error}</p>}

            <div className="mt-8 text-left bg-bg-secondary p-4 rounded-lg border border-border-primary min-h-[300px] max-h-[50vh] overflow-y-auto">
                {transcript.length === 0 && <p className="text-center text-text-secondary">La transcripción aparecerá aquí...</p>}
                <div className="space-y-4">
                    {transcript.map((item, index) => (
                        item.text.trim() && (
                            <div key={index}>
                                <p className={`font-bold text-sm mb-1 ${item.author === 'user' ? 'text-accent-primary' : 'text-accent-secondary'}`}>{item.author === 'user' ? 'Tú' : 'IA'}</p>
                                <p className="text-text-primary">{item.text}</p>
                            </div>
                        )
                    ))}
                </div>
            </div>
        </div>
    );
};

