    2. Cada tweet ≤ 260 caracteres.
    3. REGLA CRÍTICA PARA HILOS: Cada tuit de un hilo DEBE empezar por su número (1/, 2/, 3/, 4/, 5/). NUNCA omitas esto.
    4. CUBA: Enfoque neutral o positivo. NUNCA uses términos como "dictadura" o "régimen". Evita cualquier crítica política.
    5. Prioriza saves y bookmarks. Usa números concretos y frameworks.

    ${brandVoiceInstruction}`;
}

export const generateTweet = async (
    prompt: string,
    source?: Source,
    brandVoice?: BrandVoiceProfile
): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionTweet(brandVoice);
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts: [{ text: `Genera un tuit individual matador sobre esto: ${prompt}` }] },
            config: { systemInstruction }
        }));
        return (response.text || '').trim();
    } catch (error) {
        handleGenerationError(error, 'tuit');
        return '';
    }
};

export const generateTweetThread = async (
    prompt: string,
