    ]);
  };

  const openMediaPromptModal = async (type: 'image' | 'video', index: number) => {
    const existingMedia = tweets[index].media;
    const isEdit = !!existingMedia && existingMedia.type === 'image' && type === 'image';
    setMediaGenerationTarget({ type, index, isEdit });
    const tweetContent = tweets[index]?.content?.trim() || '';
    setMediaPrompt(''); 
    setIsMediaPromptModalOpen(true);
    setIsGeneratingMediaPrompt(true);
    try {
        const creativePrompt = await generateCreativeMediaPrompt(tweetContent, type, brandVoiceProfile || undefined, isEdit);
        setMediaPrompt(creativePrompt);
    } catch (error) {
        setMediaPrompt(tweetContent);
    } finally {
        setIsGeneratingMediaPrompt(false);
    }
  };

  const closeMediaPromptModal = () => {
    setIsMediaPromptModalOpen(false);
    setMediaPrompt('');
    setMediaGenerationTarget(null);
  };

  const handleConfirmMediaGeneration = () => {
    if (!mediaGenerationTarget || !mediaPrompt) return;
    const { type, index, isEdit } = mediaGenerationTarget;
    handleGenerateMedia(type, mediaPrompt, index, { aspectRatio: mediaAspectRatio, isEdit });
    closeMediaPromptModal();
  };

  const handleGenerateMedia = useCallback(async (
    type: 'image' | 'video', 
    mediaPrompt: string, 
    tweetIndex: number,
    options: { aspectRatio?: string, isEdit?: boolean } = {}
  ) => {
    tweetPreviewRefs.current[tweetIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    const existingMediaUrl = tweets[tweetIndex].media?.url;
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: true } : t));
    setIsLoading(true);
    try {
        if (type === 'image') {
            const steps = options.isEdit ? ['Editando', 'Renderizando'] : ['Prompting', 'Generando'];
            setGenerationStatus({ title: options.isEdit ? 'Editando...' : 'Generando...', steps, currentStep: 0, error: null });
            let referenceImages: { data: string; mimeType: string }[] = [];
            if (options.isEdit && existingMediaUrl && existingMediaUrl.startsWith('data:')) {
                referenceImages.push({ data: existingMediaUrl.split(',')[1], mimeType: 'image/jpeg' });
            }
            const { images } = await generateImage(mediaPrompt, options.aspectRatio, referenceImages);
            if (images && images.length > 0) {
                setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: `data:image/jpeg;base64,${images[0]}` } } : t));
            }
        } else {
            const videoSteps = ['Frames', 'IA Engine', 'Finalizando'];
            setGenerationStatus({ title: 'Video IA...', steps: videoSteps, currentStep: 0, error: null });
            const mediaUrl = await generateVideo(mediaPrompt, options.aspectRatio, (msg) => {
                 setGenerationStatus(prev => {
                     if (!prev) return null;
                     let step = prev.currentStep;
                     if (msg.includes('🤖')) step = 1;
                     else if (msg.includes('⏳')) step = 2;
                     else if (msg.includes('🎉')) step = 4;
                     return { ...prev, currentStep: step };
                 });
            });
            setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: mediaUrl } } : t));
        }
    } catch (error) {
        setGenerationStatus(prev => prev ? { ...prev, error: "Error de permisos (403)." } : null);
    } finally {
        setIsLoading(false);
        setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: false } : t));
        setTimeout(() => setGenerationStatus(null), 3000);
    }
  }, [tweets]);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (mediaTargetIndex === null) return;
    const tweetIndex = mediaTargetIndex;
    const file = event.target.files?.[0];
    if (!file) return;
    const mediaUrl = URL.createObjectURL(file);
    const mediaType = file.type.startsWith('image/') ? 'image' : 'video';
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type: mediaType, url: mediaUrl } } : t));
    setMediaTargetIndex(null);
    if(event.target) event.target.value = '';
  };

  const handleRemoveMedia = (tweetIndex: number) => {
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: null } : t));
  };

 return (
    <div className="w-full animate-fade-in">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
            <div className="flex flex-col gap-8 self-start">
                <div className="w-full flex flex-col items-center gap-6">
                    <header className="w-full max-w-7xl flex justify-between items-center px-4">
                        <div className="flex items-center justify-center gap-3">
