                        <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                    </div>
                </div>
            ))}
            {isLoading && (
                <div className="flex justify-start">
                     <div className="p-3 rounded-2xl bg-bg-primary text-text-primary rounded-bl-none border border-border-primary">
                        <LoaderIcon className="h-5 w-5" />
                    </div>
                </div>
            )}
            <div ref={chatEndRef} />
        </div>

        <div className="p-4 bg-bg-primary/50 border-t border-border-primary">
            {onQuickAction && (
                <div className="flex gap-2 mb-3">
                    <button 
                        onClick={() => onQuickAction('thread', input)}
                        disabled={isLoading || !input.trim()}
                        className="flex-1 flex items-center justify-center gap-2 py-2 px-3 bg-accent-primary/10 border border-accent-primary/30 text-accent-primary rounded-xl text-xs font-bold hover:bg-accent-primary/20 transition-all disabled:opacity-30"
                    >
                        <ListIcon className="h-4 w-4" />
                        Hilo Numerado
                    </button>
                    <button 
                        onClick={() => onQuickAction('tweet', input)}
                        disabled={isLoading || !input.trim()}
                        className="flex-1 flex items-center justify-center gap-2 py-2 px-3 bg-bg-secondary border border-border-primary text-text-primary rounded-xl text-xs font-bold hover:bg-border-primary transition-all disabled:opacity-30"
                    >
                        <SparklesIcon className="h-4 w-4" />
