            <div className="flex items-center gap-2 bg-bg-primary border border-border-primary rounded-xl p-2 focus-within:ring-2 focus-within:ring-accent-primary transition-all">
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" />
