                </button>
                <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={handleKeyPress}
                    placeholder="Escribe tu idea o pide algo..."
                    className="flex-grow bg-transparent focus:outline-none transition resize-none text-sm text-text-primary placeholder:text-text-secondary px-2 py-1 max-h-32"
                    rows={1}
