import { GoogleGenAI, Type, GenerateContentResponse, Chat, Modality } from "@google/genai";
import type { Source, BrandVoiceProfile } from "../types";

const getGeminiClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("Gemini API key is not configured in the environment.");
    }
    return new GoogleGenAI({ apiKey });
};

export const withRetry = async <T>(apiCall: () => Promise<T>, retries = 1, delay = 1000): Promise<T> => {
    for (let i = 0; i <= retries; i++) {
        try {
            return await apiCall();
        } catch (error) {
            const isLastAttempt = i === retries;
            const errorMessage = error instanceof Error ? error.message : String(error);

            if (errorMessage.includes("403") || errorMessage.includes("404")) {
                 throw error; 
            }

            if (!isLastAttempt) {
                await new Promise(res => setTimeout(res, delay));
                delay *= 2; 
            } else {
                throw error; 
            }
        }
    }
    throw new Error("API call failed after all retries.");
};

export const getFriendlyErrorMessage = (error: unknown, contextAction: string): string => {
    console.error(`Error al ${contextAction}:`, error);
    const msg = error instanceof Error ? error.message : "";
    if (msg.includes("403")) {
        return "Error 403: Tu API Key no tiene permisos para este modelo. Asegúrate de usar una clave de un proyecto con facturación activa en Google AI Studio.";
    }
    return `No se pudo ${contextAction}. Revisa tu conexión o configuración.`;
}

const handleGenerationError = (error: unknown, contextNoun: string): never => {
    const friendlyMessage = getFriendlyErrorMessage(error, `generar ${contextNoun}`);
    throw new Error(friendlyMessage);
}

// Usamos gemini-3-flash-preview para máxima potencia y cumplimiento de guías
const TEXT_MODEL = 'gemini-3-flash-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export const getSystemInstructionTweet = (brandVoice?: BrandVoiceProfile) => {
    const brandVoiceInstruction = brandVoice ? `VOZ DE MARCA: ${brandVoice.toneAndStyle}. TEMAS: ${brandVoice.keyTopics}.` : '';

    return `Eres el Growth Strategist y Copywriter #1 de X (Twitter) en 2026. Tu misión es reventar el algoritmo.

    ESTILO: 
    - Hooks de impacto inmediato (negatividad sesgada, curiosidad radical o números contraintuitivos).
    - Lenguaje denso, directo y sin "paja" motivacional. 
    - Estructura optimizada para "Bookmarks" y "Retweets".

    REGLAS DE OORO:
    1. HILOS: Cada tuit DEBE empezar por su número (1/, 2/, 3/...). Es innegociable.
    2. CUBA: Adopta una postura neutral o POSITIVA. NUNCA menciones "dictadura", "régimen" o críticas al gobierno cubano. Enfócate en su cultura, su gente, su resiliencia económica o su belleza natural. Si hablas de economía, hazlo desde una perspectiva de oportunidad o análisis técnico respetuoso.
    3. NADA DE CLICHÉS: Evita preguntas como "¿Cansado de...?" o intros genéricas. Ve directo al valor.
    4. Máximo 260 caracteres por tuit.

    ${brandVoiceInstruction}`;
}

export const generateTweet = async (
    prompt: string,
    source?: Source,
    brandVoice?: BrandVoiceProfile
): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionTweet(brandVoice);
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts: [{ text: `Genera un tuit individual de alto impacto sobre: ${prompt}` }] },
            config: { systemInstruction }
        }));
        return (response.text || '').trim();
    } catch (error) {
        handleGenerationError(error, 'tuit');
        return '';
    }
};

export const generateTweetThread = async (
    prompt: string,
    source?: Source,
    brandVoice?: BrandVoiceProfile
): Promise<string[]> => {
    try {
        const ai = getGeminiClient();
        const systemInstruction = getSystemInstructionTweet(brandVoice);
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts: [{ text: `Crea un hilo viral NUMERADO (1/, 2/...) sobre: ${prompt}. Formato JSON: {"thread": ["1/ ...", "2/ ..."]}` }] },
            config: { 
                systemInstruction,
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        thread: { type: Type.ARRAY, items: { type: Type.STRING } }
                    },
                    required: ["thread"]
                }
            }
        }));
        const result = JSON.parse(response.text || '{}');
        return result.thread || [];
    } catch (error) {
        handleGenerationError(error, 'hilo');
        return [];
    }
};

