            }
        }));
        return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || '';
    } catch { return ''; }
}

export const generatePromptIdeas = async (category: string): Promise<{ prompt: string; category: string }[]> => {
    try {
        const ai = getGeminiClient();
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts: [{ text: `3 ideas de prompts para ${category} en formato JSON.` }] },
            config: { 
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        ideas: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { prompt: { type: Type.STRING }, category: { type: Type.STRING } }, required: ["prompt", "category"] } }
                    },
                    required: ["ideas"]
                }
            }
        }));
        const result = JSON.parse(response.text || '{"ideas":[]}');
        return result.ideas || [];
    } catch { return []; }
};

export const createImagePromptFromIdea = async (idea: string, category: string): Promise<string> => {
