};

export const generateCreativeMediaPrompt = async (content: string, type: 'image' | 'video', brandVoice?: BrandVoiceProfile, isEdit: boolean = false): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const systemPrompt = `Eres un director de arte visual. Crea un prompt para ${type} basado en este contenido: "${content}". Estilo cinematográfico, iluminación dramática.`;
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: TEXT_MODEL,
            contents: { parts: [{ text: systemPrompt }] },
        }));
        return (response.text || '').trim();
    } catch (error) {
        return content;
    }
};

export const generateImage = async (prompt: string, aspectRatio: string = '1:1', referenceImages?: { data: string; mimeType: string }[]): Promise<{ images: string[], model: string }> => {
    const ai = getGeminiClient();
    try {
        const parts: any[] = [{ text: prompt }];
        if (referenceImages && referenceImages.length > 0) {
            referenceImages.forEach(img => {
                parts.unshift({ inlineData: { data: img.data, mimeType: img.mimeType } });
            });
        }
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: IMAGE_MODEL,
            contents: { parts },
            config: { imageConfig: { aspectRatio: aspectRatio as any } }
        }));
        const images: string[] = [];
        if (response.candidates?.[0]?.content?.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData?.data) images.push(part.inlineData.data);
            }
        }
        return { images, model: 'Gemini 2.5 Flash Image' };
    } catch (error) {
        handleGenerationError(error, 'imagen');
        return { images: [], model: '' };
    }
};

export const generateVideo = async (prompt: string, aspectRatio: string = '16:9', onProgress?: (status: string) => void): Promise<string> => {
     try {
        const ai = getGeminiClient();
        onProgress?.('🤖 Iniciando Veo...');
        let operation = await ai.models.generateVideos({
            model: 'veo-3.1-fast-generate-preview',
            prompt: prompt,
            config: { numberOfVideos: 1, aspectRatio: aspectRatio as any, resolution: '720p' }
        });
        while (!operation.done) {
            await new Promise(resolve => setTimeout(resolve, 10000));
            operation = await ai.operations.getVideosOperation({operation: operation});
            onProgress?.('⏳ Renderizando...');
        }
        const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
        if (!videoUri) throw new Error("Video URI missing.");
        const fetchResponse = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
        const blob = await fetchResponse.blob();
        return URL.createObjectURL(blob);
    } catch (error) {
        handleGenerationError(error, 'video');
        return '';
    }
}

export const createContentChatSession = (brandVoice?: BrandVoiceProfile): Chat => {
    const ai = getGeminiClient();
    const systemInstruction = getSystemInstructionTweet(brandVoice);
    return ai.chats.create({
        model: TEXT_MODEL,
        config: { systemInstruction, tools: [{ googleSearch: {} }] }
    });
};

export const createChatSession = (): Chat => {
     const ai = getGeminiClient();
     return ai.chats.create({
        model: TEXT_MODEL,
        config: { systemInstruction: getSystemInstructionTweet() }
    });
}

export const generateSpeech = async (text: string): Promise<string> => {
    try {
        const ai = getGeminiClient();
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: 'gemini-2.5-flash-preview-tts',
            contents: { parts: [{ text }] },
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
            }
        }));
        return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || '';
    } catch { return ''; }
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import type { Chat } from "@google/genai";
import { createContentChatSession, regenerateTweet, generateImage, generateVideo, generateCreativeMediaPrompt, generateTweetThread, generateTweet } from '../services/geminiService';
import type { XUserProfile, EditableTweet, BrandVoiceProfile, ChatMessage } from '../types';
