const DEFAULT_USER: XUserProfile = {
  id: 'user-cryptomaso',
  name: 'cryptomaso',
  handle: '@cryptomaso',
  avatarUrl: `data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%23657786'%3E%3Cpath d='M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z'/%3E%3C/svg%3E`,
  verified: true
};

const fileToBase64 = (file: Blob): Promise<{data: string, mimeType: string, name: string}> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            const name = file instanceof File ? file.name : 'audio.webm';
            resolve({ data: result.split(',')[1], mimeType: file.type, name });
        };
        reader.onerror = error => reject(error);
    });
}

const Dashboard: React.FC = () => {
  const [tweets, setTweets] = useState<EditableTweet[]>([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  const [isLoading, setIsLoading] = useState(false);
  const [generationStatus, setGenerationStatus] = useState<{ title: string; steps: string[]; currentStep: number; error: string | null; } | null>(null);

  const [isBrandVoiceModalOpen, setIsBrandVoiceModalOpen] = useState(false);
  const [brandVoiceProfile, setBrandVoiceProfile] = useState<BrandVoiceProfile | null>(null);

  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([
    {
      author: 'ai',
      content: "¡Qué pasa! Soy tu estratega viral 2026. Escribe tu idea abajo y usa los botones para generar un tuit individual o un hilo de 5 tuits."
    }
  ]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  const [isMediaPromptModalOpen, setIsMediaPromptModalOpen] = useState(false);
  const [isGeneratingMediaPrompt, setIsGeneratingMediaPrompt] = useState(false);
  const [mediaPrompt, setMediaPrompt] = useState('');
  const [mediaAspectRatio, setMediaAspectRatio] = useState('1:1');
  const [mediaGenerationTarget, setMediaGenerationTarget] = useState<{type: 'image' | 'video', index: number, isEdit: boolean} | null>(null);
  const [mediaTargetIndex, setMediaTargetIndex] = useState<number | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const tweetPreviewRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const savedProfile = localStorage.getItem('twixai-brand-voice');
    if (savedProfile) {
      setBrandVoiceProfile(JSON.parse(savedProfile));
    }
  }, []);

  useEffect(() => {
    setChatSession(createContentChatSession(brandVoiceProfile || undefined));
  }, [brandVoiceProfile]);

  const handleSaveBrandVoice = (profile: BrandVoiceProfile) => {
    setBrandVoiceProfile(profile);
    localStorage.setItem('twixai-brand-voice', JSON.stringify(profile));
  };

  const handleTweetChange = (index: number, value: string) => {
    const newTweets = [...tweets];
    newTweets[index].content = value;
    setTweets(newTweets);
  };

  const addTweetToThread = () => {
    setTweets([...tweets, { id: `tweet-${Date.now()}`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  };

  const handleQuickAction = async (type: 'tweet' | 'thread', text: string) => {
      if (!text.trim()) return;

      setIsChatLoading(true);
      // Poner los tuits actuales en estado de carga si se están regenerando todos
      setTweets(prev => prev.map(t => ({ ...t, isRegenerating: true })));
      try {
          if (type === 'thread') {
              const thread = await generateTweetThread(text, undefined, brandVoiceProfile || undefined);
              if (thread && thread.length > 0) {
                  setTweets(thread.map((content, i) => ({
                      id: `tweet-${Date.now()}-${i}`,
                      content,
                      media: null,
                      isLoadingMedia: false,
                      isCopied: false,
                      isRegenerating: false,
                  })));
                  setChatMessages(prev => [...prev, { author: 'user', content: `Generar hilo: ${text}` }, { author: 'ai', content: `Hilo viral numerado generado.` }]);
              }
          } else {
              const content = await generateTweet(text, undefined, brandVoiceProfile || undefined);
              if (content) {
                  setTweets([{
                      id: `tweet-${Date.now()}`,
                      content,
                      media: null,
                      isLoadingMedia: false,
                      isCopied: false,
                      isRegenerating: false,
                  }]);
                  setChatMessages(prev => [...prev, { author: 'user', content: `Generar tuit: ${text}` }, { author: 'ai', content: `Tuit hook generado.` }]);
              }
          }
      } catch (error) {
          const msg = error instanceof Error ? error.message : "Error 403 o de permisos.";
          setChatMessages(prev => [...prev, { author: 'ai', content: msg }]);
      } finally {
          setIsChatLoading(false);
          setTweets(prev => prev.map(t => ({ ...t, isRegenerating: false })));
      }
  };

  const handleSendMessage = async (message: string, file?: { data: string; mimeType: string; name: string }) => {
    if (!message.trim() && !file) return;

    const userMessage: ChatMessage = { author: 'user', content: message };
    setChatMessages(prev => [...prev, userMessage]);
    setIsChatLoading(true);

    try {
        if (!chatSession) throw new Error("Sesión no lista.");
        const parts: any[] = [{ text: message }];
        if (file) parts.push({ inlineData: { mimeType: file.mimeType, data: file.data } });

        const response = await chatSession.sendMessage({ message: parts });
        const assistantResponse = (response.text || '').trim();
        setChatMessages(prev => [...prev, { author: 'ai', content: assistantResponse }]);

        // Si la IA responde algo que parece un tuit largo, lo ponemos en el preview
        if (assistantResponse.length > 40 && !assistantResponse.includes("?")) {
             setTweets([{
                id: `tweet-${Date.now()}`,
                content: assistantResponse,
                media: null,
                isLoadingMedia: false,
                isCopied: false,
                isRegenerating: false,
            }]);
        }
    } catch (error) {
       setChatMessages(prev => [...prev, { author: 'ai', content: "Error al procesar. Revisa tu conexión o API Key." }]);
    } finally {
        setIsChatLoading(false);
    }
  };

  const handleCopy = (text: string, index: number) => {
    navigator.clipboard.writeText(text).then(() => {
      setTweets(prev => prev.map((t, i) => i === index ? {...t, isCopied: true} : t));
      setTimeout(() => {
        setTweets(prev => prev.map((t, i) => i === index ? {...t, isCopied: false} : t));
      }, 2000);
    });
  };

  const handleRegenerateTweet = async (index: number) => {
    const originalTweet = tweets[index];
    if (!originalTweet || originalTweet.content.trim() === '') return;
    setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: true } : t));
    try {
        const regeneratedContent = await regenerateTweet(originalTweet.content);
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, content: regeneratedContent, isRegenerating: false } : t));
    } catch (error) {
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isRegenerating: false } : t));
    }
  };

  const handleDeleteTweet = (index: number) => {
    if (tweets.length === 1) {
      setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    } else {
      setTweets(prevTweets => prevTweets.filter((_, i) => i !== index));
    }
  };

  const handleStartNew = () => {
    setTweets([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
    setChatSession(createContentChatSession(brandVoiceProfile || undefined));
    setChatMessages([
      { author: 'ai', content: "¡Limpio! Dame un nuevo ángulo y lo reventamos." }
    ]);
  };

  const openMediaPromptModal = async (type: 'image' | 'video', index: number) => {
    const existingMedia = tweets[index].media;
    const isEdit = !!existingMedia && existingMedia.type === 'image' && type === 'image';
    setMediaGenerationTarget({ type, index, isEdit });
    const tweetContent = tweets[index]?.content?.trim() || '';
    setMediaPrompt(''); 
    setIsMediaPromptModalOpen(true);
    setIsGeneratingMediaPrompt(true);
    try {
        const creativePrompt = await generateCreativeMediaPrompt(tweetContent, type, brandVoiceProfile || undefined, isEdit);
        setMediaPrompt(creativePrompt);
    } catch (error) {
        setMediaPrompt(tweetContent);
    } finally {
        setIsGeneratingMediaPrompt(false);
    }
  };

  const closeMediaPromptModal = () => {
    setIsMediaPromptModalOpen(false);
    setMediaPrompt('');
    setMediaGenerationTarget(null);
  };

  const handleConfirmMediaGeneration = () => {
    if (!mediaGenerationTarget || !mediaPrompt) return;
    const { type, index, isEdit } = mediaGenerationTarget;
    handleGenerateMedia(type, mediaPrompt, index, { aspectRatio: mediaAspectRatio, isEdit });
    closeMediaPromptModal();
  };

  const handleGenerateMedia = useCallback(async (
    type: 'image' | 'video', 
    mediaPrompt: string, 
    tweetIndex: number,
    options: { aspectRatio?: string, isEdit?: boolean } = {}
  ) => {
    tweetPreviewRefs.current[tweetIndex]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    const existingMediaUrl = tweets[tweetIndex].media?.url;
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: true } : t));
    setIsLoading(true);
    try {
        if (type === 'image') {
            const steps = options.isEdit ? ['Editando', 'Renderizando'] : ['Prompting', 'Generando'];
            setGenerationStatus({ title: options.isEdit ? 'Editando...' : 'Generando...', steps, currentStep: 0, error: null });
            let referenceImages: { data: string; mimeType: string }[] = [];
            if (options.isEdit && existingMediaUrl && existingMediaUrl.startsWith('data:')) {
                referenceImages.push({ data: existingMediaUrl.split(',')[1], mimeType: 'image/jpeg' });
            }
            const { images } = await generateImage(mediaPrompt, options.aspectRatio, referenceImages);
            if (images && images.length > 0) {
                setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: `data:image/jpeg;base64,${images[0]}` } } : t));
            }
        } else {
            const videoSteps = ['Frames', 'IA Engine', 'Finalizando'];
            setGenerationStatus({ title: 'Video IA...', steps: videoSteps, currentStep: 0, error: null });
            const mediaUrl = await generateVideo(mediaPrompt, options.aspectRatio, (msg) => {
                 setGenerationStatus(prev => {
                     if (!prev) return null;
                     let step = prev.currentStep;
                     if (msg.includes('🤖')) step = 1;
                     else if (msg.includes('⏳')) step = 2;
                     else if (msg.includes('🎉')) step = 4;
                     return { ...prev, currentStep: step };
                 });
            });
            setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type, url: mediaUrl } } : t));
        }
    } catch (error) {
        setGenerationStatus(prev => prev ? { ...prev, error: "Error de permisos (403). Revisa tu API Key." } : null);
    } finally {
        setIsLoading(false);
        setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, isLoadingMedia: false } : t));
        setTimeout(() => setGenerationStatus(null), 3000);
    }
  }, [tweets]);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (mediaTargetIndex === null) return;
    const tweetIndex = mediaTargetIndex;
    const file = event.target.files?.[0];
    if (!file) return;
    const mediaUrl = URL.createObjectURL(file);
    const mediaType = file.type.startsWith('image/') ? 'image' : 'video';
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: { type: mediaType, url: mediaUrl } } : t));
    setMediaTargetIndex(null);
    if(event.target) event.target.value = '';
  };

  const handleRemoveMedia = (tweetIndex: number) => {
    setTweets(prev => prev.map((t, i) => i === tweetIndex ? { ...t, media: null } : t));
  };

 return (
    <div className="w-full animate-fade-in">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
            {/* Panel Izquierdo: Chat y Estrategia */}
            <div className="flex flex-col gap-8 self-start">
                <div className="w-full flex flex-col items-center gap-6">
                    <header className="w-full max-w-7xl flex justify-between items-center px-4">
                        <div className="flex items-center justify-center gap-3">
                            <LogoIcon className="h-8 w-8"/>
                            <h1 className="text-xl font-bold tracking-tight">Growth Studio</h1>
                        </div>
                        <button onClick={() => setIsBrandVoiceModalOpen(true)} className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-all border-2 border-border-primary bg-bg-secondary text-text-primary hover:border-accent-primary shadow-sm">
                            <SparklesIcon className="h-5 w-5 text-accent-primary"/>
                            <span>Voz de Marca</span>
                        </button>
                    </header>

                    <div className="w-full max-w-3xl flex flex-col gap-4">
                        <ChatHistory 
                            messages={chatMessages} 
                            onSendMessage={handleSendMessage} 
                            isLoading={isChatLoading} 
                            fileToBase64={fileToBase64}
                            onQuickAction={handleQuickAction}
                        />
                        <div className="text-center">
                            <p className="text-[10px] text-text-secondary uppercase tracking-[0.2em] font-black opacity-40">IA Content Strategist v2.6</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Panel Derecho: Preview y Edición de Tuits Individuales */}
            <div className="lg:sticky lg:top-28 h-fit max-h-[calc(100vh-8rem)]">
                <div className="flex justify-between items-center mb-6">
                    <div className="flex items-center gap-3">
                        <h3 className="text-2xl font-black text-text-primary italic uppercase tracking-tighter">Preview Viral</h3>
                        <div className="h-2 w-2 rounded-full bg-success animate-pulse"></div>
                    </div>
                    <button onClick={handleStartNew} className="flex items-center gap-2 px-4 py-2 rounded-full text-sm font-bold transition-all bg-bg-secondary border border-border-primary text-text-secondary hover:text-text-primary hover:border-text-primary">
                        <PlusIcon className="h-4 w-4" /> Nuevo
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 max-h-[calc(100vh-12rem)] space-y-4 no-scrollbar pb-10">
                      {tweets.map((tweet, index) => (
                          <div key={tweet.id} ref={el => { tweetPreviewRefs.current[index] = el; }} className="animate-fade-in" style={{animationDelay: `${index * 0.1}s`}}>
                              <TweetPreview
                                  tweet={{ 
                                      id: tweet.id, 
                                      content: tweet.content, 
                                      author: DEFAULT_USER, 
                                      media: tweet.media || undefined, 
                                      public_metrics: { like_count: 0, retweet_count: 0, impression_count: 0, reply_count: 0, quote_count: 0 }, 
                                      created_at: new Date().toISOString(), 
                                  }}
                                  editableTweet={tweet}
                                  isGenerating={isLoading}
                                  onCopy={() => handleCopy(tweet.content, index)}
                                  onGenerateMedia={(type) => openMediaPromptModal(type, index)}
                                  onUploadMedia={() => { setMediaTargetIndex(index); fileInputRef.current?.click(); }}
                                  onRemoveMedia={() => handleRemoveMedia(index)}
                                  onTweetChange={(value) => handleTweetChange(index, value)}
                                  onRegenerate={() => handleRegenerateTweet(index)}
                                  onDeleteTweet={() => handleDeleteTweet(index)}
                              />
                          </div>
                      ))}
                      {tweets.length > 0 && tweets.some(t => t.content) && (
                        <button onClick={addTweetToThread} className="w-full py-4 border-2 border-dashed border-border-primary rounded-xl text-text-secondary hover:text-accent-primary hover:border-accent-primary transition-all font-black text-xs uppercase tracking-widest bg-bg-secondary/30">
                            + Añadir Tuit al Hilo
                        </button>
                      )}
                </div>
            </div>
        </div>

        {generationStatus && <GenerationStatus title={generationStatus.title} steps={generationStatus.steps} currentStepIndex={generationStatus.currentStep} error={generationStatus.error} />}
        <BrandVoiceModal isOpen={isBrandVoiceModalOpen} onClose={() => setIsBrandVoiceModalOpen(false)} onSave={handleSaveBrandVoice} />
        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*,video/*" />

        {isMediaPromptModalOpen && (
            <div className="fixed inset-0 bg-bg-primary/95 backdrop-blur-xl flex items-center justify-center p-4 z-50 animate-fade-in">
                <div className="bg-bg-secondary border border-border-primary rounded-2xl p-8 w-full max-w-lg relative shadow-2xl ring-1 ring-white/10">
                    <h2 className="text-2xl font-black mb-4 uppercase tracking-tighter text-text-primary">
                        {mediaGenerationTarget?.isEdit ? 'Refinar Visual' : `Generar Visual IA`}
                    </h2>
                    <div className="relative mb-6">
                        <textarea
                            value={mediaPrompt}
                            onChange={(e) => setMediaPrompt(e.target.value)}
                            placeholder={isGeneratingMediaPrompt ? "Imaginando..." : "Describe la escena perfecta..."}
                            className={`w-full bg-bg-primary border border-border-primary rounded-xl p-4 focus:ring-2 focus:ring-accent-primary focus:outline-none transition min-h-[140px] text-text-primary placeholder:text-text-secondary/50 ${isGeneratingMediaPrompt ? 'opacity-30' : 'opacity-100'}`}
                            rows={5}
                            disabled={isGeneratingMediaPrompt}
                        />
                        {isGeneratingMediaPrompt && (
                            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                <LoaderIcon className="h-10 w-10 text-accent-primary" />
                            </div>
                        )}
                    </div>
                    <div className="flex justify-end gap-3">
                        <button onClick={closeMediaPromptModal} className="px-6 py-3 rounded-full font-bold bg-bg-primary text-text-primary border border-border-primary hover:bg-border-primary transition-all">Cancelar</button>
                        <button onClick={handleConfirmMediaGeneration} disabled={!mediaPrompt || isGeneratingMediaPrompt} className="px-8 py-3 rounded-full font-bold bg-accent-primary text-bg-primary hover:opacity-90 transition-all shadow-glow-primary active:scale-95">
                            {mediaGenerationTarget?.isEdit ? 'Aplicar' : 'Crear'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        <style>{`
            .animate-fade-in { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
            @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        `}</style>
    </div>
  );
