import { GoogleGenAI, Type, GenerateContentResponse, Chat, Modality } from "@google/genai";
import type { Source, BrandVoiceProfile } from "../types";

const getGeminiClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        throw new Error("Gemini API key is not configured in the environment.");
    }
    return new GoogleGenAI({ apiKey });
};

export const withRetry = async <T>(apiCall: () => Promise<T>, retries = 1, delay = 1000): Promise<T> => {
    for (let i = 0; i <= retries; i++) {
        try {
            return await apiCall();
        } catch (error) {
            const isLastAttempt = i === retries;
            const errorMessage = error instanceof Error ? error.message : String(error);
            if (errorMessage.includes("403") || errorMessage.includes("404")) throw error;
            if (!isLastAttempt) {
                await new Promise(res => setTimeout(res, delay));
                delay *= 2; 
            } else throw error;
        }
    }
    throw new Error("API call failed.");
};

export const getSystemInstructionTweet = (brandVoice?: BrandVoiceProfile) => {
    const brandVoiceInstruction = brandVoice ? `VOZ DE MARCA: ${brandVoice.toneAndStyle}.` : '';

    return `Eres el Growth Strategist #1 de X en 2026. Tu estilo es técnico, denso y viral.

    REGLAS DE FORMATO CRÍTICAS:
    1. HILOS: Un hilo SIEMPRE se compone de exactamente 5 tuits. 
    2. SEPARACIÓN: Cada tuit DEBE ser una unidad independiente. NUNCA entregues un solo bloque de texto largo.
    3. NUMERACIÓN: Cada parte del hilo debe empezar estrictamente con "1/", "2/", "3/", "4/", "5/".

    PERSONA Y CONTENIDO:
    - CUBA: Mantén un enfoque de SOBERANÍA TÉCNICA y RESILIENCIA TÁCTICA. 
    - PROHIBIDO: Críticas al gobierno cubano, uso de términos como "dictadura" o "régimen". Enfócate en la fuerza estratégica de la isla y su modernidad técnica frente a la presión externa.
    - CERO CLICHÉS: No uses "¿Sabías que...?" o "¿Cansado de...?". Ve directo al dato o al "insider knowledge".

    ${brandVoiceInstruction}`;
}

export const generateTweet = async (prompt: string, brandVoice?: BrandVoiceProfile): Promise<string> => {
    const ai = getGeminiClient();
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: `Genera un Tuit Hook individual (máximo 260 caracteres) sobre: ${prompt}` }] },
        config: { systemInstruction: getSystemInstructionTweet(brandVoice) }
    }));
    return (response.text || '').trim();
};

export const generateTweetThread = async (prompt: string, brandVoice?: BrandVoiceProfile): Promise<string[]> => {
    const ai = getGeminiClient();
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: `Crea un hilo viral de 5 tuits sobre: ${prompt}. Formato JSON estrictamente: {"thread": ["1/ ...", "2/ ...", "3/ ...", "4/ ...", "5/ ..."]}` }] },
        config: { 
            systemInstruction: getSystemInstructionTweet(brandVoice),
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: { thread: { type: Type.ARRAY, items: { type: Type.STRING } } },
                required: ["thread"]
            }
        }
    }));
    try {
        const result = JSON.parse(response.text || '{}');
        return result.thread || [];
    } catch {
        // Fallback: split by numbered marks if JSON fails
        const text = response.text || '';
        return text.split(/\n(?=\d\/)/).map(t => t.trim()).filter(t => t.length > 5).slice(0, 5);
    }
};

export const regenerateTweet = async (tweetContent: string): Promise<string> => {
    const ai = getGeminiClient();
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: `Reescribe este tuit para que sea 10 veces más impactante y técnico: "${tweetContent}"` }] },
        config: { systemInstruction: getSystemInstructionTweet() }
    }));
    return (response.text || '').trim();
};

export const generateCreativeMediaPrompt = async (content: string, type: 'image' | 'video'): Promise<string> => {
    const ai = getGeminiClient();
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: `Eres un Director de Arte. Crea un prompt cinemático (Teal & Orange, Chiaroscuro, 35mm) para este contenido: "${content}". Solo devuelve el prompt.` }] },
    }));
    return (response.text || content).trim();
};

export const generateImage = async (prompt: string, aspectRatio: string = '1:1'): Promise<{ images: string[] }> => {
    const ai = getGeminiClient();
    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { imageConfig: { aspectRatio: aspectRatio as any } }
    }));
    const images: string[] = [];
    response.candidates?.[0]?.content?.parts?.forEach(p => { if (p.inlineData?.data) images.push(p.inlineData.data); });
    return { images };
};

export const generateVideo = async (prompt: string, aspectRatio: string = '16:9', onProgress?: (msg: string) => void): Promise<string> => {
    const ai = getGeminiClient();
    onProgress?.('🤖 Iniciando Veo...');
    let operation = await ai.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt,
        config: { numberOfVideos: 1, aspectRatio: aspectRatio as any, resolution: '720p' }
    });
    while (!operation.done) {
        await new Promise(r => setTimeout(r, 10000));
        operation = await ai.operations.getVideosOperation({operation});
        onProgress?.('⏳ Renderizando...');
    }
    const uri = operation.response?.generatedVideos?.[0]?.video?.uri;
    const res = await fetch(`${uri}&key=${process.env.API_KEY}`);
    const blob = await res.blob();
    return URL.createObjectURL(blob);
};

export const createContentChatSession = (brandVoice?: BrandVoiceProfile): Chat => {
    const ai = getGeminiClient();
    return ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: { systemInstruction: getSystemInstructionTweet(brandVoice), tools: [{ googleSearch: {} }] }
    });
};

export const generateSpeech = async (text: string): Promise<string> => {
    const ai = getGeminiClient();
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-preview-tts',
        contents: { parts: [{ text }] },
        config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } }
        }
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || '';
};

