// Fixed: Allow second parameter to be either BrandVoiceProfile or Source to fix errors in CreateTweet.tsx
export const generateTweet = async (prompt: string, config?: BrandVoiceProfile | Source): Promise<string> => {
    const ai = getGeminiClient();

    const brandVoice = (config && 'toneAndStyle' in config) ? config as BrandVoiceProfile : undefined;
    const source = (config && 'web' in config) ? config as Source : undefined;

    const finalPrompt = source 
        ? `CONTEXTO WEB: ${source.web.title} (${source.web.uri})\n\nGenera un Tuit Hook individual basado en este contexto: ${prompt}`
        : `Genera un Tuit Hook individual (máximo 260 caracteres) sobre: ${prompt}`;

    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: finalPrompt }] },
        config: { systemInstruction: getSystemInstructionTweet(brandVoice) }
    }));
    return (response.text || '').trim();
};

// Fixed: Allow second parameter to be either BrandVoiceProfile or Source
export const generateTweetThread = async (prompt: string, config?: BrandVoiceProfile | Source): Promise<string[]> => {
    const ai = getGeminiClient();

    const brandVoice = (config && 'toneAndStyle' in config) ? config as BrandVoiceProfile : undefined;
    const source = (config && 'web' in config) ? config as Source : undefined;

    const finalPrompt = source 
        ? `CONTEXTO WEB: ${source.web.title} (${source.web.uri})\n\nCrea un hilo viral de 5 tuits sobre: ${prompt}. Formato JSON estrictamente: {"thread": ["1/ ...", "2/ ...", "3/ ...", "4/ ...", "5/ ..."]}`
        : `Crea un hilo viral de 5 tuits sobre: ${prompt}. Formato JSON estrictamente: {"thread": ["1/ ...", "2/ ...", "3/ ...", "4/ ...", "5/ ..."]}`;

    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: finalPrompt }] },
        config: { 
            systemInstruction: getSystemInstructionTweet(brandVoice),
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: { thread: { type: Type.ARRAY, items: { type: Type.STRING } } },
                required: ["thread"]
            }
        }
    }));
    try {
        const result = JSON.parse(response.text || '{}');
        return result.thread || [];
    } catch {
        // Fallback: split by numbered marks if JSON fails
        const text = response.text || '';
        return text.split(/\n(?=\d\/)/).map(t => t.trim()).filter(t => t.length > 5).slice(0, 5);
    }
};

