// Fixed: Exported getFriendlyErrorMessage to fix error in ChatBot.tsx
export const getFriendlyErrorMessage = (error: any, action: string): string => {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes("403")) return `Error 403: No tienes permisos para ${action}. Revisa tu API Key.`;
    if (msg.includes("404")) return `Error 404: Recurso no encontrado al intentar ${action}.`;
    if (msg.includes("429")) return `Error 429: Demasiadas solicitudes. Espera un momento.`;
    return `Error al ${action}: ${msg}`;
};

