export const generateTweetThread = async (prompt: string, config?: BrandVoiceProfile | Source): Promise<string[]> => {
    const ai = getGeminiClient();
    const brandVoice = (config && 'toneAndStyle' in config) ? config as BrandVoiceProfile : undefined;

    const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: { parts: [{ text: `Crea un hilo viral de exactamente 5 tuits sobre: ${prompt}. Estilo humano. Cada tuit DEBE empezar con "🧵1/5", "🧵2/5", etc. Formato JSON: {"thread": ["🧵1/5 ...", "🧵2/5 ...", "🧵3/5 ...", "🧵4/5 ...", "🧵5/5 ..."]}` }] },
        config: { 
            systemInstruction: getSystemInstructionTweet(brandVoice),
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: { 
                    thread: { 
                        type: Type.ARRAY, 
                        items: { type: Type.STRING },
                        description: "Array de 5 tuits, cada uno comenzando con 🧵N/5"
                    } 
                },
                required: ["thread"]
            }
        }
    }));
    try {
        const result = JSON.parse(response.text || '{}');
        return (result.thread || []).slice(0, 5);
    } catch {
        const text = response.text || '';
        // Fallback blindado para detectar el emoji y la fracción
        const matches = text.match(/🧵[1-5]\/5[\s\S]+?(?=\n🧵[1-5]\/5|$)/g);
        if (matches) return matches.map(t => t.trim()).slice(0, 5);
        return text.split(/\n(?=🧵\d\/5)/).map(t => t.trim()).filter(t => t.length > 5).slice(0, 5);
    }
};

