import React, { useState, useRef, useEffect, useCallback } from 'react';
import type { Chat } from "@google/genai";
import { createContentChatSession, regenerateTweet, generateImage, generateVideo, generateCreativeMediaPrompt, generateTweetThread, generateTweet } from '../services/geminiService';
import type { XUserProfile, EditableTweet, BrandVoiceProfile, ChatMessage } from '../types';
import TweetPreview from './TweetPreview';
import GenerationStatus from './GenerationStatus';
import BrandVoiceModal from './BrandVoiceModal';
import ChatHistory from './ChatHistory';
import LogoIcon from './icons/LogoIcon';
import PlusIcon from './icons/PlusIcon';
import SparklesIcon from './icons/SparklesIcon';
import LoaderIcon from './icons/LoaderIcon';

const DEFAULT_USER: XUserProfile = {
  id: 'user-cryptomaso',
  name: 'cryptomaso',
  handle: '@cryptomaso',
  avatarUrl: `data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='%23657786'%3E%3Cpath d='M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z'/%3E%3C/svg%3E`,
  verified: true
};

const Dashboard: React.FC = () => {
  const [tweets, setTweets] = useState<EditableTweet[]>([{ id: `tweet-0`, content: '', media: null, isLoadingMedia: false, isCopied: false, isRegenerating: false }]);
  const [generationStatus, setGenerationStatus] = useState<{ title: string; steps: string[]; currentStep: number; error: string | null; } | null>(null);
  const [brandVoiceProfile, setBrandVoiceProfile] = useState<BrandVoiceProfile | null>(null);
  const [isBrandVoiceModalOpen, setIsBrandVoiceModalOpen] = useState(false);
  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([{ author: 'ai', content: "Growth Strategist listo. ¿Qué impacto vamos a crear hoy?" }]);
  const [isChatLoading, setIsChatLoading] = useState(false);
  const [isMediaModalOpen, setIsMediaModalOpen] = useState(false);
  const [mediaPrompt, setMediaPrompt] = useState('');
  const [mediaTarget, setMediaTarget] = useState<{index: number, type: 'image' | 'video'} | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('twixai-brand-voice');
    if (saved) setBrandVoiceProfile(JSON.parse(saved));
    setChatSession(createContentChatSession(saved ? JSON.parse(saved) : undefined));
  }, []);

  const handleQuickAction = async (type: 'tweet' | 'thread', text: string) => {
    if (!text.trim()) return;
    setIsChatLoading(true);
    setTweets(prev => prev.map(t => ({ ...t, isRegenerating: true })));

    try {
        if (type === 'thread') {
            const threadParts = await generateTweetThread(text, brandVoiceProfile || undefined);
            if (threadParts.length > 0) {
                setTweets(threadParts.map((content, i) => ({
                    id: `tweet-${Date.now()}-${i}`,
                    content,
                    media: null,
                    isLoadingMedia: false,
                    isCopied: false,
                    isRegenerating: false,
                })));
                setChatMessages(prev => [...prev, { author: 'user', content: `Hilo: ${text}` }, { author: 'ai', content: "Hilo generado con éxito." }]);
            }
        } else {
            const content = await generateTweet(text, brandVoiceProfile || undefined);
            setTweets([{
                id: `tweet-${Date.now()}`,
                content,
                media: null,
                isLoadingMedia: false,
                isCopied: false,
                isRegenerating: false,
            }]);
            setChatMessages(prev => [...prev, { author: 'user', content: `Tuit: ${text}` }, { author: 'ai', content: "Hook generado con éxito." }]);
        }
    } catch (e) {
        setChatMessages(prev => [...prev, { author: 'ai', content: "Error de API. Revisa tu conexión." }]);
    } finally {
        setIsChatLoading(false);
        setTweets(prev => prev.map(t => ({ ...t, isRegenerating: false })));
    }
  };

  const handleSendMessage = async (message: string) => {
    if (!message.trim()) return;
    setChatMessages(prev => [...prev, { author: 'user', content: message }]);
    setIsChatLoading(true);
    try {
        const response = await chatSession!.sendMessage({ message });
        const text = response.text || '';
        setChatMessages(prev => [...prev, { author: 'ai', content: text }]);

        // Blindaje de fragmentación en el chat: busca patrones de hilos
        if (text.includes("🧵") || (text.includes("1/5") && text.includes("2/5"))) {
            const parts = text.split(/(?=🧵\d\/5|\d\/5)/g).map(t => t.trim()).filter(t => t.length > 10);
            if (parts.length > 1) {
                setTweets(parts.slice(0, 5).map((content, i) => ({
                    id: `tweet-chat-${Date.now()}-${i}`,
                    content,
                    media: null,
                    isLoadingMedia: false,
                    isCopied: false,
                    isRegenerating: false,
                })));
                return;
            }
        }

        if (text.length > 20) {
            setTweets([{
                id: `tweet-chat-${Date.now()}`,
                content: text,
                media: null,
                isLoadingMedia: false,
                isCopied: false,
                isRegenerating: false,
            }]);
        }
    } catch (e) {
        setChatMessages(prev => [...prev, { author: 'ai', content: "Fallo en el chat." }]);
    } finally {
        setIsChatLoading(false);
    }
  };

  const handleGenerateMedia = async (type: 'image' | 'video', index: number) => {
    setMediaTarget({ index, type });
    setMediaPrompt('');
    setIsMediaModalOpen(true);
    const creative = await generateCreativeMediaPrompt(tweets[index].content, type);
    setMediaPrompt(creative);
  };

  const confirmMedia = async () => {
    if (!mediaTarget) return;
    const { index, type } = mediaTarget;
    setIsMediaModalOpen(false);
    setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: true } : t));

    try {
        if (type === 'image') {
            const { images } = await generateImage(mediaPrompt);
            setTweets(prev => prev.map((t, i) => i === index ? { ...t, media: { type: 'image', url: `data:image/jpeg;base64,${images[0]}` } } : t));
        } else {
            const url = await generateVideo(mediaPrompt);
            setTweets(prev => prev.map((t, i) => i === index ? { ...t, media: { type: 'video', url } } : t));
        }
    } catch {
        console.error("Multimedia failed");
    } finally {
        setTweets(prev => prev.map((t, i) => i === index ? { ...t, isLoadingMedia: false } : t));
    }
  };

  return (
    <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in">
        <div className="space-y-6">
            <header className="flex justify-between items-center">
                <div className="flex items-center gap-2"><LogoIcon className="h-8 w-8"/><h1 className="text-xl font-bold italic tracking-tighter">STUDIO V2</h1></div>
                <button onClick={() => setIsBrandVoiceModalOpen(true)} className="p-2 bg-bg-secondary rounded-full border border-border-primary"><SparklesIcon className="h-5 w-5 text-accent-primary"/></button>
            </header>
            <ChatHistory messages={chatMessages} onSendMessage={handleSendMessage} isLoading={isChatLoading} fileToBase64={async () => ({data:'', mimeType:'', name:''})} onQuickAction={handleQuickAction} />
        </div>

        <div className="lg:sticky lg:top-24 h-fit max-h-[85vh] overflow-y-auto no-scrollbar space-y-4 pb-10">
            <div className="flex justify-between items-center">
                <h2 className="text-2xl font-black uppercase italic tracking-tighter">Preview</h2>
                <button onClick={() => setTweets([{ id: '0', content: '', media: null, isLoadingMedia: false, isCopied: false }])} className="text-xs font-bold text-text-secondary uppercase">+ Limpiar</button>
            </div>
            {tweets.map((t, i) => (
                <TweetPreview 
                    key={t.id} 
                    tweet={{ id: t.id, content: t.content, author: DEFAULT_USER, media: t.media || undefined, public_metrics: { like_count: 0, retweet_count: 0, impression_count: 0, reply_count: 0, quote_count: 0 }, created_at: new Date().toISOString() }}
                    editableTweet={t}
                    onTweetChange={(v) => { const n = [...tweets]; n[i].content = v; setTweets(n); }}
                    onCopy={() => navigator.clipboard.writeText(t.content)}
                    onRegenerate={async () => { const n = [...tweets]; n[i].isRegenerating = true; setTweets(n); const r = await regenerateTweet(t.content); n[i].content = r; n[i].isRegenerating = false; setTweets(n); }}
                    onDeleteTweet={() => setTweets(tweets.filter((_, idx) => idx !== i))}
                    onGenerateMedia={(type) => handleGenerateMedia(type as any, i)}
                    onRemoveMedia={() => { const n = [...tweets]; n[i].media = null; setTweets(n); }}
                />
            ))}
        </div>

        {generationStatus && <GenerationStatus {...generationStatus} currentStepIndex={generationStatus.currentStep} />}
        {isMediaModalOpen && (
            <div className="fixed inset-0 bg-bg-primary/95 backdrop-blur-xl flex items-center justify-center p-4 z-50">
                <div className="bg-bg-secondary border border-border-primary p-8 rounded-2xl w-full max-w-lg shadow-2xl">
                    <h3 className="text-xl font-black mb-4 uppercase">IA Visual</h3>
                    <textarea value={mediaPrompt} onChange={(e) => setMediaPrompt(e.target.value)} className="w-full bg-bg-primary border border-border-primary rounded-xl p-4 mb-6 min-h-[150px]" />
                    <div className="flex justify-end gap-3">
                        <button onClick={() => setIsMediaModalOpen(false)} className="px-6 py-2 rounded-full font-bold bg-bg-primary border border-border-primary">Cancelar</button>
                        <button onClick={confirmMedia} className="px-8 py-2 rounded-full font-bold bg-accent-primary text-bg-primary">Crear</button>
                    </div>
                </div>
            </div>
        )}
        <BrandVoiceModal isOpen={isBrandVoiceModalOpen} onClose={() => setIsBrandVoiceModalOpen(false)} onSave={(p) => { setBrandVoiceProfile(p); localStorage.setItem('twixai-brand-voice', JSON.stringify(p)); }} />
    </div>
  );
};

export default Dashboard;
